import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../contexts/AuthContext';
import { Button } from '../components/ui/button';
import { toast } from 'sonner';
import { ArrowLeft, Clock, Play } from 'lucide-react';

const BACKEND_URL = process.env.REACT_APP_BACKEND_URL;
const API = `${BACKEND_URL}/api`;

export default function WorkoutDetailPage() {
  const { routineId } = useParams();
  const navigate = useNavigate();
  const { getAuthHeader } = useAuth();
  const [routine, setRoutine] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchRoutine();
  }, [routineId]);

  const fetchRoutine = async () => {
    try {
      const response = await axios.get(`${API}/routines/${routineId}`, {
        headers: getAuthHeader()
      });
      setRoutine(response.data);
    } catch (error) {
      toast.error('Failed to load workout');
      navigate('/');
    } finally {
      setLoading(false);
    }
  };

  const handleStartWorkout = async () => {
    try {
      const response = await axios.post(
        `${API}/workouts/start`,
        { routine_id: routineId },
        { headers: getAuthHeader() }
      );
      navigate(`/workout/${response.data.id}/active`);
    } catch (error) {
      toast.error('Failed to start workout');
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-[#0A0A0A] flex items-center justify-center">
        <div className="text-white text-lg">Loading...</div>
      </div>
    );
  }

  if (!routine) return null;

  return (
    <div className="min-h-screen bg-[#0A0A0A]">
      {/* Header */}
      <header className="bg-[#141414] border-b border-[#27272A]/40 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex items-center gap-4">
          <Button
            variant="ghost"
            size="icon"
            onClick={() => navigate('/')}
            className="text-[#A1A1AA] hover:text-white hover:bg-[#1A1A1A]"
            data-testid="back-button"
          >
            <ArrowLeft className="w-5 h-5" />
          </Button>
          <h1 className="barlow text-2xl font-black tracking-tighter text-white" data-testid="workout-title">
            {routine.name}
          </h1>
        </div>
      </header>

      {/* Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Hero Image */}
        <div className="mb-8 rounded-md overflow-hidden h-64 sm:h-80">
          <img
            src={routine.cover_image}
            alt={routine.name}
            className="w-full h-full object-cover"
          />
        </div>

        {/* Info */}
        <div className="mb-8">
          <h2 className="barlow text-4xl sm:text-5xl font-black tracking-tighter text-white mb-4">
            {routine.name}
          </h2>
          <p className="text-[#A1A1AA] text-lg tracking-wide mb-4">{routine.description}</p>
          <div className="flex items-center gap-6 text-[#71717A]">
            <div className="flex items-center gap-2">
              <Play className="w-5 h-5" />
              <span className="text-sm uppercase tracking-widest font-bold">
                {routine.exercises.length} Exercises
              </span>
            </div>
            <div className="flex items-center gap-2">
              <Clock className="w-5 h-5" />
              <span className="text-sm uppercase tracking-widest font-bold">
                ~{routine.estimated_duration} Minutes
              </span>
            </div>
          </div>
        </div>

        {/* Exercise List */}
        <div className="mb-8">
          <h3 className="barlow text-2xl font-black tracking-tight text-white mb-4">Exercises</h3>
          <div className="space-y-3">
            {routine.exercises.map((exercise, index) => (
              <div
                key={exercise.exercise_id}
                className="bg-[#1A1A1A] border border-[#27272A] rounded-md p-4 flex items-center gap-4"
                data-testid={`exercise-item-${index}`}
              >
                <div className="w-16 h-16 rounded-md overflow-hidden flex-shrink-0">
                  <img
                    src={exercise.image_url}
                    alt={exercise.exercise_name}
                    className="w-full h-full object-cover"
                  />
                </div>
                <div className="flex-1">
                  <h4 className="barlow text-lg font-bold tracking-tight text-white mb-1">
                    {exercise.exercise_name}
                  </h4>
                  <p className="text-[#A1A1AA] text-sm">{exercise.muscle_group}</p>
                </div>
                <div className="text-right">
                  <p className="barlow text-xl font-bold text-white">{exercise.sets} × {exercise.reps}</p>
                  <p className="text-[#71717A] text-xs uppercase tracking-widest">Sets × Reps</p>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Start Button - Fixed on Mobile */}
        <div className="sticky bottom-0 left-0 right-0 p-4 bg-[#0A0A0A] border-t border-[#27272A] sm:relative sm:p-0 sm:border-0">
          <Button
            onClick={handleStartWorkout}
            className="w-full bg-[#007AFF] hover:bg-[#0066DD] text-white font-bold py-4 text-lg"
            data-testid="start-workout-button"
          >
            Start Workout
          </Button>
        </div>
      </main>
    </div>
  );
}
